I'll note that it did not produce such on main [so: 14].

# more writes_nulls_check.sh 
#! /bin/sh
pkg install e2fsprogs
mdconfig -u0 -s512M
mke2fs -t ext4 /dev/md0
mount -t ext2fs /dev/md0 /mnt
rm -f writes_nulls_check.c
cat <<'EOF' >writes_nulls_check.c
// Example compile/link, producing a.out: cc -std=c17 -pedantic -Wall -Wextra writes_nulls_check.c -owrites_nulls_check

#include <err.h>    // err related
#include <fcntl.h>  // open related
#include <string.h> // strlen
#include <unistd.h> // fsync related

int main(void)
{
        const char* const fn   = "/mnt/writes_nulls_check.txt";
        const char* const S    = "hello world\n";
        const size_t      n    = strlen(S);

        int fd = open(fn, O_WRONLY|O_CREAT, 0666);
        if (fd == -1)
                err(1, "%s: open failed", fn);
        if (write(fd, S, n) != n)
                err(1, "%s: write failed", fn);
        if (close(fd) == -1)
                err(1, "%s: close failed", fn);

        fd = open(fn, O_WRONLY | O_TRUNC | O_DIRECT, 0666);
        if (fd == -1)
                err(1, "%s: open failed", fn);
        if (write(fd, S, n) != n)
                err(1, "%s: write failed", fn);
        if (fsync(fd))
                err(1, "fsync failed");
        if (close(fd) == -1)
                err(1, "%s: close failed", fn);
        return 0;
}
EOF
cc -std=c17 -pedantic -Wall -Wextra writes_nulls_check.c -owrites_nulls_check
./writes_nulls_check
hd /mnt/writes_nulls_check.txt
umount /mnt
mdconfig -d -u0
# Leave writes_nulls_check.c and writes_nulls_check in place for reference.
